html:
{%- set doc = frappe.get_doc("Ticket Booking", doc.name) -%}
{%- set seats = doc.seats or [] -%}
{%- set seat_labels = seats | map(attribute="seat_label") | join(", ") -%}
{%- set site_url = frappe.utils.get_url() -%}

<style>
  @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700&display=swap');

  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    font-family: 'Montserrat', Arial, sans-serif;
    background: #0d0d1a;
    color: #fff;
    padding: 20px;
  }

  .ticket {
    max-width: 680px;
    margin: 0 auto;
    background: #1a1a2e;
    border-radius: 16px;
    overflow: hidden;
    border: 1px solid #2a2a4a;
    box-shadow: 0 8px 32px rgba(0,0,0,0.5);
  }

  /* ── Header ── */
  .ticket-header {
    background: linear-gradient(135deg, #16213e 0%, #0f3460 100%);
    padding: 28px 32px;
    display: flex;
    align-items: center;
    gap: 24px;
    border-bottom: 2px solid #e94560;
  }

  .movie-poster {
    width: 90px;
    height: 120px;
    border-radius: 8px;
    object-fit: cover;
    border: 2px solid #e94560;
    flex-shrink: 0;
  }

  .movie-poster-placeholder {
    width: 90px;
    height: 120px;
    border-radius: 8px;
    background: #0f3460;
    border: 2px solid #e94560;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 36px;
    flex-shrink: 0;
  }

  .header-info { flex: 1; }

  .movie-title {
    font-size: 26px;
    font-weight: 700;
    color: #fff;
    line-height: 1.2;
    margin-bottom: 8px;
  }

  .badge {
    display: inline-block;
    background: #e94560;
    color: #fff;
    font-size: 10px;
    font-weight: 700;
    padding: 3px 10px;
    border-radius: 20px;
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 12px;
  }

  .header-meta {
    font-size: 13px;
    color: #a0a0c0;
    line-height: 1.8;
  }

  /* ── Details Grid ── */
  .ticket-body { padding: 28px 32px; }

  .details-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
    margin-bottom: 24px;
  }

  .detail-item label {
    display: block;
    font-size: 10px;
    font-weight: 700;
    color: #e94560;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 4px;
  }

  .detail-item span {
    font-size: 15px;
    font-weight: 600;
    color: #fff;
  }

  /* ── Divider ── */
  .ticket-divider {
    display: flex;
    align-items: center;
    margin: 20px -32px;
    position: relative;
  }

  .ticket-divider::before,
  .ticket-divider::after {
    content: "";
    flex: 1;
    height: 1px;
    background: #2a2a4a;
  }

  .divider-circle {
    width: 20px;
    height: 20px;
    background: #0d0d1a;
    border-radius: 50%;
    margin: 0 -2px;
    flex-shrink: 0;
  }

  /* ── Seats ── */
  .seats-section { margin-bottom: 24px; }

  .seats-section label {
    display: block;
    font-size: 10px;
    font-weight: 700;
    color: #e94560;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 10px;
  }

  .seat-chips { display: flex; flex-wrap: wrap; gap: 8px; }

  .seat-chip {
    background: #0f3460;
    border: 1px solid #e94560;
    color: #fff;
    font-size: 13px;
    font-weight: 700;
    padding: 6px 14px;
    border-radius: 6px;
    letter-spacing: 0.5px;
  }

  /* ── Footer ── */
  .ticket-footer {
    background: #0f0f1f;
    padding: 20px 32px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    border-top: 1px solid #2a2a4a;
  }

  .booking-id-block label {
    display: block;
    font-size: 10px;
    color: #e94560;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 4px;
  }

  .booking-id {
    font-size: 18px;
    font-weight: 700;
    letter-spacing: 2px;
    color: #fff;
  }

  .amount-block { text-align: right; }

  .amount-block label {
    display: block;
    font-size: 10px;
    color: #e94560;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 4px;
  }

  .amount {
    font-size: 24px;
    font-weight: 700;
    color: #4CAF50;
  }

  .qr-block { text-align: center; }

  .qr-block img {
    width: 90px;
    height: 90px;
    border: 2px solid #2a2a4a;
    border-radius: 8px;
  }

  .qr-block p {
    font-size: 9px;
    color: #555;
    margin-top: 4px;
  }

  /* ── Notice ── */
  .ticket-notice {
    background: #16213e;
    padding: 12px 32px;
    text-align: center;
    font-size: 11px;
    color: #6060a0;
    border-top: 1px solid #2a2a4a;
  }
</style>

<div class="ticket">

  <!-- Header -->
  <div class="ticket-header">
    {% if doc.movie_poster %}
      <img class="movie-poster"
           src="{{ site_url }}{{ doc.movie_poster }}"
           alt="{{ doc.movie_title }}">
    {% else %}
      <div class="movie-poster-placeholder">🎬</div>
    {% endif %}

    <div class="header-info">
      <div class="badge">Movie Ticket</div>
      <div class="movie-title">{{ doc.movie_title }}</div>
      <div class="header-meta">
        📅 {{ frappe.format(doc.show_date, {"fieldtype": "Date"}) }}<br>
        🕐 {{ (doc.start_time | string)[:5] }}<br>
        🏛 {{ doc.theatre }}
      </div>
    </div>
  </div>

  <!-- Body -->
  <div class="ticket-body">

    <div class="details-grid">
      <div class="detail-item">
        <label>Screen</label>
        <span>{{ doc.screen }}</span>
      </div>
      <div class="detail-item">
        <label>No. of Seats</label>
        <span>{{ doc.number_of_seats }}</span>
      </div>
      <div class="detail-item">
        <label>Customer</label>
        <span>{{ doc.customer_name }}</span>
      </div>
      <div class="detail-item">
        <label>Payment Status</label>
        <span>{{ doc.payment_status }}</span>
      </div>
    </div>

    <div class="ticket-divider">
      <div class="divider-circle"></div>
      <div class="divider-circle" style="margin-left:auto;"></div>
    </div>

    <!-- Seats -->
    <div class="seats-section">
      <label>Your Seats</label>
      <div class="seat-chips">
        {% for seat in seats %}
          <div class="seat-chip">{{ seat.seat_label }}</div>
        {% endfor %}
      </div>
    </div>

  </div>

  <!-- Footer -->
  <div class="ticket-footer">
    <div class="booking-id-block">
      <label>Booking ID</label>
      <div class="booking-id">{{ doc.name }}</div>
    </div>

    {% if doc.qr_code_url %}
    <div class="qr-block">
      <img src="{{ site_url }}{{ doc.qr_code_url }}" alt="QR Code">
      <p>Scan at entry</p>
    </div>
    {% endif %}

    <div class="amount-block">
      <label>Total Amount</label>
      <div class="amount">₹{{ "{:,.2f}".format(doc.total_amount) }}</div>
    </div>
  </div>

  <!-- Notice -->
  <div class="ticket-notice">
    Please arrive 15 minutes early · Carry valid photo ID · No outside food allowed
  </div>

</div>
